    container.addEventListener('scroll', () => {
      this.checkInfiniteLoop();
    });
  }
  // CONTROL CON FLECHAS
  scrollCarousel(direction) {
    if (this.isCarouselScrolling) return;
    const container = this.carouselContainer.nativeElement;
    const cardWidth = 350 + 30; // ancho de tarjeta + gap
    const scrollAmount = cardWidth;
    this.isCarouselScrolling = true;
    if (direction === 'left') {
      container.scrollBy({
        left: -scrollAmount,
        behavior: 'smooth'
      });
    } else {
      container.scrollBy({
        left: scrollAmount,
        behavior: 'smooth'
      });
    }
    setTimeout(() => {
      this.isCarouselScrolling = false;
      this.checkInfiniteLoop();
    }, 500);
  }
  // DRAG CON MOUSE/TOUCH
  onDragStart(event) {
    this.isDragging = true;
    const clientX = this.getPositionX(event);
    this.startPos = clientX;
    const container = this.carouselContainer.nativeElement;
    this.prevTranslate = container.scrollLeft;
    // Prevenir selección de texto mientras se arrastra
    event.preventDefault();
  }
  onDragMove(event) {
    if (!this.isDragging) return;
    const container = this.carouselContainer.nativeElement;
    const currentPosition = this.getPositionX(event);
    const diff = this.startPos - currentPosition;
    container.scrollLeft = this.prevTranslate + diff;
  }
  onDragEnd() {
    if (!this.isDragging) return;
    this.isDragging = false;
    this.checkInfiniteLoop();
  }
